function data = mdp_SubtractJaw(data, varargin)%MDP_SUBTRACTJAW  - MVIEW dataproc that subtracts vertical JAW mvt%%	varargin{1} - cellstr name list defaults to {'JAW','TT','LL'}%% appends TTZsubJAW, LLZsubJAW signals%% Example 1 (DATA includes JAW, TT and LL trajectories):% mview(...,'DPROC','mdp_SubtractJaw, ...)%% Example 2 (apply only to TT); note that if a trajectory list is specified JAW should be its first member:% mview(...,'DPROC',{'mdp_LipAperture',{'mdp_SubtractJaw',{'JAW','TT'}}}, ...)%% Example 2 (different names for JAW and TT trajectories):% mview(...,'DPROC',{'mdp_LipAperture',{'mdp_SubtractJaw',{'LI','TTM'}}}, ...)% mkt 12/08% mkt 02/17 mods% mkt 11/21 include LL% mkt 06/23 arbitrary trajectory listif isempty(varargin{1}),	traj = {'JAW','TT','LL'};else,	traj = upper(varargin(1:end-1));end;names = upper({data.NAME});JAW = find(strcmp(traj{1}, names));jawName = traj{1};if isempty(JAW), error('can''t find JAW (%s) in data', jawName); end;XYZ = 'XYZ';ci = 3;		% Zif size(data(JAW).SIGNAL,2) < 3, ci = 2; end;traj(1) = [];nTraj = length(traj);for ti = 1 : nTraj,	k = find(strcmp(traj{ti}, names));	if isempty(k), error('can''t find %s in data', traj{ti}); end;	data(end+1) = data(k);	data(end).NAME = sprintf('%s%ssub%s',traj{ti},XYZ(ci),jawName);	data(end).SIGNAL = data(k).SIGNAL(:,ci) - data(JAW).SIGNAL(:,ci);	minS = min(data(end).SIGNAL);	maxS = max(data(end).SIGNAL);	spread = maxS - minS;	data(end).SPREAD = [minS-spread*.1 maxS+spread*.1];	%pad	data(end).NCOMPS = 1;end